import re

def parse_youtube_links(text):
    """解析YouTube链接，支持多种格式"""
    links = []
    for line in text.strip().split('\n'):
        line = line.strip()
        if not line or line.startswith('#'):
            continue

        # 完整URL格式
        if 'youtube.com' in line or 'youtu.be' in line:
            links.append(line)
        # 纯视频ID格式（11位字符）
        elif re.match(r'^[a-zA-Z0-9_-]{11}$', line):
            links.append(f"https://www.youtube.com/watch?v={line}")
        else:
            links.append(line)

    return {"links": links, "count": len(links)}

result = parse_youtube_links(input.get('youtube_links', ''))
print(f"解析完成: {result['count']} 个链接")
result

def aggregate_results(process_results):
    """聚合多个视频的处理结果"""
    if not isinstance(process_results, list):
        process_results = [process_results]

    success_count = 0
    fail_count = 0
    processed = []
    failed = []

    for result in process_results:
        if isinstance(result, dict):
            if result.get('status') == 'success':
                success_count += 1
                processed.append({
                    'video_id': result.get('video_id'),
                    'files': result.get('files', {})
                })
            else:
                fail_count += 1
                failed.append({
                    'video_id': result.get('video_id', 'unknown'),
                    'reason': result.get('error', '未知错误')
                })
        elif isinstance(result, str) and result.startswith('FAILED'):
            fail_count += 1
            failed.append({'reason': result})

    total = success_count + fail_count

    return {
        'status': 'completed' if fail_count == 0 else 'partially_completed' if success_count > 0 else 'failed',
        'total_count': total,
        'success_count': success_count,
        'fail_count': fail_count,
        'processed_videos': processed,
        'failed_videos': failed
    }

result = aggregate_results(input.get('process_results', []))
print(f"处理完成: {result['success_count']}/{result['total_count']} 成功")
result
